% V_on and I_on as a function of R w/ Data
R_vals = linspace(0, 1e6, 1e6);

RGB = orderedcolors("gem");
default_colors = rgb2hex(RGB);

figure(); %[output:41cb26c4]
yyaxis left %[output:41cb26c4]
loglog(R_vals, U_T ./ R_vals) %[output:41cb26c4]
hold on; %[output:41cb26c4]
xlabel('Resistance in Series (R)') %[output:41cb26c4]
ylabel('I_{on} (A)') %[output:41cb26c4]
yyaxis right %[output:41cb26c4]
ylabel('V_{on} (V)') %[output:41cb26c4]
semilogx(R_vals, log(((U_T./R_vals)/I_s) + 1) .* U_T) %[output:41cb26c4]

yyaxis left %[output:41cb26c4]
semilogx(120, U_T/120, 'x', Color=default_colors(5), LineWidth=2) %[output:41cb26c4]
semilogx(10e3, U_T/10e3, 'x', Color=default_colors(6),LineWidth=2) %[output:41cb26c4]
semilogx(200e3, U_T/200e3, 'x', Color=default_colors(7), LineWidth=2) %[output:41cb26c4]
yyaxis right %[output:41cb26c4]
semilogx(120, log(((U_T/120)/I_s) + 1) * U_T, 'x', Color=default_colors(5), LineWidth=2) %[output:41cb26c4]
semilogx(10e3, log(((U_T/10e3)/I_s) + 1) * U_T, 'x', Color=default_colors(6), LineWidth=2) %[output:41cb26c4]
semilogx(200e3, log(((U_T/200e3)/I_s) + 1) * U_T, 'x', Color=default_colors(7), LineWidth=2) %[output:41cb26c4]

title('V_{on} and I_{on} with respect to R') %[output:41cb26c4]
legend('I_{on} = U_{T}/R Theoretical Fit', 'R = 120 \Omega', 'R = 10 k\Omega', 'R = 200 k\Omega', 'V_{on} = ln(U_{T}/R)/I_{s} + 1 Theoretical Fit', '', '', '',Location='southoutside') %[output:41cb26c4] %[output:9c187ba7]

